export type AnswerOption = {
  label: string
  text: string
}

export type Question = {
  id: string
  text: string
  options: [AnswerOption, AnswerOption, AnswerOption, AnswerOption]
  correctLabel: string
}

export type Quiz = {
  id: string
  title: string
  questions: Question[]
  createdAt: string
}

export type QuizAttemptAnswer = {
  questionId: string
  selectedLabel: string
  correct: boolean
}

export type QuizAttempt = {
  quizId: string
  answers: QuizAttemptAnswer[]
  score: number
  total: number
}

export type AppView =
  | { kind: 'home' }
  | { kind: 'create'; draft: DraftQuiz }
  | { kind: 'add-question'; draft: DraftQuiz }
  | { kind: 'take'; quizId: string; questionIndex: number; answers: QuizAttemptAnswer[] }
  | { kind: 'results'; attempt: QuizAttempt; quiz: Quiz }

export type DraftQuiz = {
  title: string
  questions: Question[]
}

import type { Quiz } from './types'

const DATA_DIR = `${import.meta.dir}/data`
const QUIZZES_FILE = `${DATA_DIR}/quizzes.json`

export const loadQuizzes = async (): Promise<Quiz[]> => {
  const file = Bun.file(QUIZZES_FILE)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Quiz[]
}

export const saveQuizzes = async (quizzes: Quiz[]): Promise<void> => {
  await Bun.write(QUIZZES_FILE, JSON.stringify(quizzes, null, 2))
}

export const addQuiz = async (quiz: Quiz): Promise<void> => {
  const quizzes = await loadQuizzes()
  quizzes.push(quiz)
  await saveQuizzes(quizzes)
}

export const getQuiz = async (id: string): Promise<Quiz | undefined> => {
  const quizzes = await loadQuizzes()
  return quizzes.find((q) => q.id === id)
}

export const deleteQuiz = async (id: string): Promise<void> => {
  const quizzes = await loadQuizzes()
  await saveQuizzes(quizzes.filter((q) => q.id !== id))
}

