export const renderHome = (quizzes: Quiz[]): string => {
  const quizList = quizzes.length === 0
    ? h('div', { style: styles.emptyState },
        h('p', {}, 'No quizzes yet. Create one to get started!'),
      )
    : h(Fragment, {},
        ...quizzes.map((quiz) =>
          h('div', { style: styles.card },
            h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
              h('div', {},
                h('strong', {}, quiz.title),
                h('div', { style: { fontSize: '13px', color: '#666', marginTop: '4px' } },
                  `${quiz.questions.length} question${quiz.questions.length !== 1 ? 's' : ''}`,
                ),
              ),
              h('div', {},
                h('button', { style: styles.button, 'p-trigger': `take-quiz:${quiz.id}` }, 'Take Quiz'),
                h('button', { style: styles.buttonDanger, 'p-trigger': `delete-quiz:${quiz.id}` }, 'Delete'),
              ),
            ),
          ),
        ),
      )

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Quiz Builder'),
    h('button', { style: styles.button, 'p-trigger': 'create-quiz' }, '+ New Quiz'),
    h('div', { style: { marginTop: '20px' } }, quizList),
  )
}

export const renderCreateQuiz = (draft: DraftQuiz): string => {
