        ...draft.questions.map((q, i) =>
          h('div', { style: { ...styles.card, display: 'flex', alignItems: 'flex-start' } },
            h('span', { style: styles.questionBadge }, `${i + 1}`),
            h('div', {},
              h('div', { style: { fontWeight: '600' } }, q.text),
              h('div', { style: { fontSize: '13px', color: '#666', marginTop: '4px' } },
                ...q.options.map((opt) =>
                  h('div', {},
                    opt.label === q.correctLabel
                      ? h('span', { style: styles.correct }, `${opt.label}. ${opt.text} ✓`)
                      : h('span', {}, `${opt.label}. ${opt.text}`),
                  ),
                ),
              ),
            ),
          ),
        ),
      )
    : null

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Create Quiz'),
    h('div', { style: { marginBottom: '16px' } },
      h('label', { style: styles.label }, 'Quiz Title'),
      h('input', {
        style: styles.input,
        type: 'text',
        placeholder: 'Enter quiz title...',
        value: draft.title,
        'p-target': 'quiz-title',
      }),
    ),
    questionsList,
    h('div', { style: { display: 'flex', gap: '8px' } },
      h('button', { style: styles.button, 'p-trigger': 'add-question' }, '+ Add Question'),
      draft.questions.length > 0
        ? h('button', { style: styles.button, 'p-trigger': 'save-quiz' }, 'Save Quiz')
        : null,
      h('button', { style: styles.buttonSecondary, 'p-trigger': 'cancel-create' }, 'Cancel'),
    ),
  )
}

