export const renderTakeQuestion = (
  quiz: Quiz,
  questionIndex: number,
  selectedLabel: string | null,
): string => {
  const question = quiz.questions[questionIndex]
  const total = quiz.questions.length
  const isLast = questionIndex === total - 1

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, quiz.title),
    h('div', { style: styles.progressText }, `Question ${questionIndex + 1} of ${total}`),
    h('div', { style: styles.card },
      h('h2', { style: { ...styles.subheading, marginBottom: '16px' } }, question.text),
      ...question.options.map((opt) => {
        const isSelected = selectedLabel === opt.label
        const optStyle = {
          ...styles.optionRow,
          padding: '10px 12px',
          borderRadius: '6px',
          border: isSelected ? '2px solid #0f3460' : '1px solid #ddd',
          backgroundColor: isSelected ? '#e8eef6' : '#fff',
          cursor: 'pointer',
          marginBottom: '8px',
        }
        return h('div', { style: optStyle, 'p-trigger': `select-answer:${opt.label}` },
          h('input', {
            type: 'radio',
            name: 'answer',
            value: opt.label,
            checked: isSelected ? 'checked' : undefined,
            style: styles.radio,
          }),
          h('span', { style: { fontWeight: '600', minWidth: '20px' } }, `${opt.label}.`),
          h('span', {}, opt.text),
        )
      }),
    ),
    h('div', { style: { display: 'flex', gap: '8px' } },
      selectedLabel
        ? h('button', { style: styles.button, 'p-trigger': 'next-question' },
            isLast ? 'Finish Quiz' : 'Next',
          )
        : null,
      h('button', { style: styles.buttonSecondary, 'p-trigger': 'quit-quiz' }, 'Quit'),
    ),
  )
}

export const renderResults = (attempt: QuizAttempt, quiz: Quiz): string => {
  const percentage = attempt.total > 0 ? Math.round((attempt.score / attempt.total) * 100) : 0

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Quiz Results'),
    h('div', { style: styles.scoreBox },
      h('div', { style: styles.scoreLarge }, `${attempt.score}/${attempt.total}`),
      h('div', { style: { fontSize: '16px', marginTop: '8px' } }, `${percentage}% correct`),
    ),
    h('h2', { style: styles.subheading }, 'Question Breakdown'),
    ...quiz.questions.map((question, i) => {
      const answer = attempt.answers[i]
      const selectedOption = question.options.find((o) => o.label === answer?.selectedLabel)
      const correctOption = question.options.find((o) => o.label === question.correctLabel)

      return h('div', { style: styles.card },
        h('div', { style: { display: 'flex', alignItems: 'flex-start' } },
          h('span', { style: styles.questionBadge }, `${i + 1}`),
          h('div', { style: { flex: '1' } },
            h('div', { style: { fontWeight: '600', marginBottom: '8px' } }, question.text),
            answer?.correct
              ? h('div', { style: styles.correct },
                  `Your answer: ${answer.selectedLabel}. ${selectedOption?.text ?? ''} — Correct`,
                )
              : h(Fragment, {},
                  h('div', { style: styles.incorrect },
                    `Your answer: ${answer?.selectedLabel ?? '—'}. ${selectedOption?.text ?? 'No answer'} — Incorrect`,
                  ),
                  h('div', { style: { ...styles.correct, marginTop: '4px' } },
                    `Correct answer: ${question.correctLabel}. ${correctOption?.text ?? ''}`,
                  ),
                ),
          ),
        ),
      )
    }),
    h('div', { style: { marginTop: '20px' } },
      h('button', { style: styles.button, 'p-trigger': 'retake-quiz' }, 'Retake Quiz'),
      h('button', { style: styles.buttonSecondary, 'p-trigger': 'go-home' }, 'Back to Quizzes'),
    ),
  )
}

import type { Quiz, Question, QuizAttempt, QuizAttemptAnswer, AppView, DraftQuiz, AnswerOption } from './types'
import { loadQuizzes, addQuiz, getQuiz, deleteQuiz } from './store'
import { renderHome, renderCreateQuiz, renderAddQuestion, renderTakeQuestion, renderResults } from './render'

type HandlerResult = {
  html: string
  view: AppView
}

export const handleGoHome = async (): Promise<HandlerResult> => {
  const quizzes = await loadQuizzes()
  return {
    html: renderHome(quizzes),
    view: { kind: 'home' },
  }
}

export const handleCreateQuiz = (): HandlerResult => {
  const draft: DraftQuiz = { title: '', questions: [] }
  return {
    html: renderCreateQuiz(draft),
    view: { kind: 'create', draft },
  }
}

export const handleAddQuestion = (draft: DraftQuiz): HandlerResult => {
  const questionNumber = draft.questions.length + 1
  return {
    html: renderAddQuestion(questionNumber),
    view: { kind: 'add-question', draft },
  }
}

export const handleConfirmQuestion = (
  draft: DraftQuiz,
  questionText: string,
  options: [string, string, string, string],
  correctLabel: string,
): HandlerResult => {
  const labels = ['A', 'B', 'C', 'D'] as const
  const answerOptions: [AnswerOption, AnswerOption, AnswerOption, AnswerOption] = [
    { label: labels[0], text: options[0] },
    { label: labels[1], text: options[1] },
    { label: labels[2], text: options[2] },
    { label: labels[3], text: options[3] },
  ]

  const question: Question = {
    id: crypto.randomUUID(),
    text: questionText,
    options: answerOptions,
    correctLabel,
  }

  const updatedDraft: DraftQuiz = {
    ...draft,
    questions: [...draft.questions, question],
  }

  return {
    html: renderCreateQuiz(updatedDraft),
    view: { kind: 'create', draft: updatedDraft },
  }
}

export const handleUpdateTitle = (draft: DraftQuiz, title: string): DraftQuiz => {
  return { ...draft, title }
}

export const handleSaveQuiz = async (draft: DraftQuiz): Promise<HandlerResult> => {
  const quiz: Quiz = {
    id: crypto.randomUUID(),
    title: draft.title,
    questions: draft.questions,
    createdAt: new Date().toISOString(),
  }

  await addQuiz(quiz)
  return handleGoHome()
}

export const handleDeleteQuiz = async (quizId: string): Promise<HandlerResult> => {
  await deleteQuiz(quizId)
  return handleGoHome()
}

export const handleStartQuiz = async (quizId: string): Promise<HandlerResult> => {
  const quiz = await getQuiz(quizId)
  if (!quiz || quiz.questions.length === 0) {
    return handleGoHome()
  }

  return {
    html: renderTakeQuestion(quiz, 0, null),
    view: { kind: 'take', quizId, questionIndex: 0, answers: [] },
  }
}

export const handleSelectAnswer = async (
  view: Extract<AppView, { kind: 'take' }>,
  selectedLabel: string,
): Promise<HandlerResult> => {
  const quiz = await getQuiz(view.quizId)
  if (!quiz) return handleGoHome()

  return {
    html: renderTakeQuestion(quiz, view.questionIndex, selectedLabel),
    view: { ...view },
  }
}

export const handleNextQuestion = async (
  view: Extract<AppView, { kind: 'take' }>,
  selectedLabel: string,
): Promise<HandlerResult> => {
  const quiz = await getQuiz(view.quizId)
  if (!quiz) return handleGoHome()

  const currentQuestion = quiz.questions[view.questionIndex]
  const answer: QuizAttemptAnswer = {
    questionId: currentQuestion.id,
    selectedLabel,
    correct: selectedLabel === currentQuestion.correctLabel,
  }

  const updatedAnswers = [...view.answers, answer]
  const nextIndex = view.questionIndex + 1

  if (nextIndex >= quiz.questions.length) {
    const score = updatedAnswers.filter((a) => a.correct).length
    const attempt: QuizAttempt = {
      quizId: view.quizId,
      answers: updatedAnswers,
      score,
      total: quiz.questions.length,
    }

    return {
      html: renderResults(attempt, quiz),
      view: { kind: 'results', attempt, quiz },
    }
  }

  return {
    html: renderTakeQuestion(quiz, nextIndex, null),
    view: { kind: 'take', quizId: view.quizId, questionIndex: nextIndex, answers: updatedAnswers },
  }
}

export const handleRetakeQuiz = async (quizId: string): Promise<HandlerResult> => {
  return handleStartQuiz(quizId)
}

import type { AppView } from './types'
import {
  handleGoHome,
  handleCreateQuiz,
  handleAddQuestion,
  handleConfirmQuestion,
  handleUpdateTitle,
  handleSaveQuiz,
  handleDeleteQuiz,
  handleStartQuiz,
  handleSelectAnswer,
  handleNextQuestion,
  handleRetakeQuiz,
} from './handlers'

type TriggerEvent = {
  type: string
  payload?: string
  formData?: Record<string, string>
}

let currentView: AppView = { kind: 'home' }
let currentSelectedLabel: string | null = null

const parseTrigger = (trigger: string): { type: string; payload?: string } => {
  const colonIndex = trigger.indexOf(':')
  if (colonIndex === -1) return { type: trigger }
  return { type: trigger.slice(0, colonIndex), payload: trigger.slice(colonIndex + 1) }
}

export const dispatch = async (event: TriggerEvent): Promise<string> => {
  const { type, payload } = event.type.includes(':')
    ? parseTrigger(event.type)
    : { type: event.type, payload: event.payload }

  const formData = event.formData ?? {}

  switch (type) {
    case 'go-home':
    case 'cancel-create':
    case 'quit-quiz': {
      const result = await handleGoHome()
      currentView = result.view
      currentSelectedLabel = null
      return result.html
    }

    case 'create-quiz': {
      const result = handleCreateQuiz()
      currentView = result.view
      return result.html
    }

    case 'add-question': {
      if (currentView.kind === 'create') {
        if (formData['quiz-title']) {
          currentView = { ...currentView, draft: handleUpdateTitle(currentView.draft, formData['quiz-title']) }
        }
        const result = handleAddQuestion(currentView.draft)
        currentView = result.view
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'confirm-question': {
      if (currentView.kind === 'add-question') {
        const questionText = formData['question-text'] ?? ''
        const options: [string, string, string, string] = [
          formData['option-A'] ?? '',
          formData['option-B'] ?? '',
          formData['option-C'] ?? '',
          formData['option-D'] ?? '',
        ]
        const correctLabel = formData['correct-answer'] ?? 'A'

        const result = handleConfirmQuestion(currentView.draft, questionText, options, correctLabel)
        currentView = result.view
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'cancel-question': {
      if (currentView.kind === 'add-question') {
        const draft = currentView.draft
        const { renderCreateQuiz } = await import('./render')
        currentView = { kind: 'create', draft }
        return renderCreateQuiz(draft)
      }
      return (await handleGoHome()).html
    }

    case 'save-quiz': {
      if (currentView.kind === 'create') {
        if (formData['quiz-title']) {
          currentView = { ...currentView, draft: handleUpdateTitle(currentView.draft, formData['quiz-title']) }
        }
        const result = await handleSaveQuiz(currentView.draft)
        currentView = result.view
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'delete-quiz': {
      if (payload) {
        const result = await handleDeleteQuiz(payload)
        currentView = result.view
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'take-quiz': {
      if (payload) {
        const result = await handleStartQuiz(payload)
        currentView = result.view
        currentSelectedLabel = null
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'select-answer': {
      if (currentView.kind === 'take' && payload) {
        currentSelectedLabel = payload
        const result = await handleSelectAnswer(currentView, payload)
        currentView = result.view
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'next-question': {
      if (currentView.kind === 'take' && currentSelectedLabel) {
        const result = await handleNextQuestion(currentView, currentSelectedLabel)
        currentView = result.view
        currentSelectedLabel = null
        return result.html
      }
      return (await handleGoHome()).html
    }

    case 'retake-quiz': {
      if (currentView.kind === 'results') {
        const result = await handleRetakeQuiz(currentView.quiz.id)
        currentView = result.view
        currentSelectedLabel = null
        return result.html
      }
      return (await handleGoHome()).html
    }

    default: {
      const result = await handleGoHome()
      currentView = result.view
      return result.html
    }
  }
}

export const init = async (): Promise<string> => {
  const result = await handleGoHome()
  currentView = result.view
  return result.html
}
